    private static readonly Dictionary<string, Patient> PatientStore = new Dictionary<string, Patient>();
    private static readonly Dictionary<string, MedicalRecord> RecordStore = new Dictionary<string, MedicalRecord>();
    private static readonly Dictionary<string, List<Medication>> MedicationStore = new Dictionary<string, List<Medication>>();
    private static readonly Dictionary<string, List<LabResult>> LabResultStore = new Dictionary<string, List<LabResult>>();
    private static readonly Dictionary<string, List<Allergy>> AllergyStore = new Dictionary<string, List<Allergy>>();
    private static readonly Dictionary<string, List<VitalSigns>> VitalSignsStore = new Dictionary<string, List<VitalSigns>>();
    private static readonly List<AuditEntry> AuditLog = new List<AuditEntry>();
    private static readonly object LockObject = new object();

    private string GenerateTransactionId()
    {
        return $"TXN-{Guid.NewGuid():N}".Substring(0, 20).ToUpper();
    }

    private void LogAudit(string action, string resourceType, string resourceId, string details)
    {
        var entry = new AuditEntry
        {
            AuditId = Guid.NewGuid().ToString(),
            Timestamp = DateTime.UtcNow,
            UserId = GetCurrentUserId(),
            Action = action,
            ResourceType = resourceType,
            ResourceId = resourceId,
            IPAddress = GetClientIPAddress(),
            Details = details
        };

        lock (LockObject)
        {
            AuditLog.Add(entry);
        }

        Console.WriteLine($"[AUDIT] {entry.Timestamp:O} | {entry.Action} | {entry.ResourceType}/{entry.ResourceId} | User: {entry.UserId}");
    }

    private string GetCurrentUserId()
    {
        try
        {
            var context = OperationContext.Current;
            if (context?.ServiceSecurityContext?.PrimaryIdentity != null)
            {
                return context.ServiceSecurityContext.PrimaryIdentity.Name;
            }
        }
        catch { }
        return "SYSTEM";
    }

    private string GetClientIPAddress()
    {
        try
        {
            var context = OperationContext.Current;
            if (context != null)
            {
                var remoteEndpoint = context.IncomingMessageProperties[RemoteEndpointMessageProperty.Name]
                    as RemoteEndpointMessageProperty;
                return remoteEndpoint?.Address ?? "Unknown";
            }
        }
        catch { }
        return "Unknown";
    }

    private void ValidatePatient(Patient patient)
    {
        var errors = new List<string>();

        if (string.IsNullOrWhiteSpace(patient.FirstName))
            errors.Add("First name is required.");
        if (string.IsNullOrWhiteSpace(patient.LastName))
            errors.Add("Last name is required.");
        if (patient.DateOfBirth == default)
            errors.Add("Date of birth is required.");
        if (patient.DateOfBirth > DateTime.UtcNow)
            errors.Add("Date of birth cannot be in the future.");

        if (errors.Count > 0)
        {
            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "VALIDATION_ERROR",
                    ErrorMessage = "Patient validation failed.",
                    Details = string.Join(" ", errors),
                    Timestamp = DateTime.UtcNow,
                    TransactionId = GenerateTransactionId()
                },
                new FaultReason("Patient validation failed."));
        }
    }

    public HealthcareServiceResponse RegisterPatient(Patient patient)
    {
        try
        {
            ValidatePatient(patient);

            if (string.IsNullOrWhiteSpace(patient.PatientId))
            {
                patient.PatientId = $"PAT-{Guid.NewGuid():N}".Substring(0, 16).ToUpper();
            }

            lock (LockObject)
            {
                if (PatientStore.ContainsKey(patient.PatientId))
                {
                    throw new FaultException<HealthcareFault>(
                        new HealthcareFault
                        {
                            ErrorCode = "DUPLICATE_PATIENT",
                            ErrorMessage = $"Patient with ID {patient.PatientId} already exists.",
                            Timestamp = DateTime.UtcNow,
                            TransactionId = GenerateTransactionId()
                        },
                        new FaultReason("Duplicate patient record."));
                }

                PatientStore[patient.PatientId] = patient;
            }

            string maskedSSN = !string.IsNullOrEmpty(patient.SocialSecurityNumber) && patient.SocialSecurityNumber.Length >= 4
                ? $"***-**-{patient.SocialSecurityNumber.Substring(patient.SocialSecurityNumber.Length - 4)}"
                : "N/A";

            LogAudit("CREATE", "Patient", patient.PatientId,
                $"Registered patient: {patient.FirstName} {patient.LastName}, SSN: {maskedSSN}");

            return new HealthcareServiceResponse
            {
                Success = true,
                Message = $"Patient registered successfully with ID: {patient.PatientId}",
                TransactionId = GenerateTransactionId(),
                Timestamp = DateTime.UtcNow
            };
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            LogAudit("ERROR", "Patient", patient?.PatientId ?? "Unknown",
                $"Registration failed: {ex.Message}");

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred while registering the patient.",
                    Timestamp = DateTime.UtcNow,
                    TransactionId = GenerateTransactionId()
                },
                new FaultReason("Internal server error."));
        }
    }

    public HealthcareServiceResponse UpdatePatient(Patient patient)
    {
        try
        {
            ValidatePatient(patient);

            lock (LockObject)
            {
                if (!PatientStore.ContainsKey(patient.PatientId))
                {
                    throw new FaultException<HealthcareFault>(
