    public PatientSearchResponse SearchPatients(PatientSearchCriteria criteria)
    {
        try
        {
            var results = new List<Patient>();

            lock (LockObject)
            {
                foreach (var patient in PatientStore.Values)
                {
                    bool match = true;

                    if (!string.IsNullOrWhiteSpace(criteria.PatientId))
                        match &= patient.PatientId == criteria.PatientId;

                    if (!string.IsNullOrWhiteSpace(criteria.FirstName))
                        match &= patient.FirstName != null &&
                                 patient.FirstName.IndexOf(criteria.FirstName, StringComparison.OrdinalIgnoreCase) >= 0;

                    if (!string.IsNullOrWhiteSpace(criteria.LastName))
                        match &= patient.LastName != null &&
                                 patient.LastName.IndexOf(criteria.LastName, StringComparison.OrdinalIgnoreCase) >= 0;

                    if (criteria.DateOfBirth.HasValue)
                        match &= patient.DateOfBirth.Date == criteria.DateOfBirth.Value.Date;

                    if (!string.IsNullOrWhiteSpace(criteria.SocialSecurityNumber))
                        match &= patient.SocialSecurityNumber == criteria.SocialSecurityNumber;

                    if (match)
                        results.Add(patient);
                }
            }

            LogAudit("SEARCH", "Patient", "N/A",
                $"Patient search performed. Results: {results.Count}");

            return new PatientSearchResponse
            {
                Success = true,
                Message = $"Found {results.Count} patient(s).",
                TransactionId = GenerateTransactionId(),
                Timestamp = DateTime.UtcNow,
                Patients = results,
                TotalCount = results.Count
            };
        }
        catch (Exception ex)
        {
            LogAudit("ERROR", "Patient", "N/A", $"Search failed: {ex.Message}");

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred during search.",
                    Timestamp = DateTime.UtcNow,
                    TransactionId = GenerateTransactionId()
                },
                new FaultReason("Internal server error."));
        }
    }

