    public MedicalRecordResponse GetMedicalRecords(string patientId, DateTime? fromDate, DateTime? toDate)
    {
        try
        {
            var results = new List<MedicalRecord>();

            lock (LockObject)
            {
                foreach (var record in RecordStore.Values)
                {
                    if (record.PatientId != patientId)
                        continue;

                    if (fromDate.HasValue && record.RecordDate < fromDate.Value)
                        continue;

                    if (toDate.HasValue && record.RecordDate > toDate.Value)
                        continue;

                    results.Add(record);
                }
            }

            LogAudit("READ", "MedicalRecord", patientId,
                $"Medical records accessed. Count: {results.Count}");

            return new MedicalRecordResponse
            {
                Success = true,
                Message = $"Found {results.Count} medical record(s).",
                TransactionId = GenerateTransactionId(),
                Timestamp = DateTime.UtcNow,
                MedicalRecords = results,
                TotalCount = results.Count
            };
        }
        catch (Exception ex)
        {
            LogAudit("ERROR", "MedicalRecord", patientId,
                $"Retrieval failed: {ex.Message}");

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred.",
                    Timestamp = DateTime.UtcNow,
                    TransactionId = GenerateTransactionId()
                },
                new FaultReason("Internal server error."));
        }
