            lock (LockObject)
            {
                if (!PatientStore.ContainsKey(patientId))
                {
                    throw new FaultException<HealthcareFault>(
                        new HealthcareFault
                        {
                            ErrorCode = "PATIENT_NOT_FOUND",
                            ErrorMessage = $"Patient {patientId} not found.",
                            Timestamp = DateTime.UtcNow,
                            TransactionId = GenerateTransactionId()
                        },
                        new FaultReason("Patient not found."));
                }

                if (!MedicationStore.ContainsKey(patientId))
                    MedicationStore[patientId] = new List<Medication>();

                medication.IsActive = true;
                if (medication.StartDate == default)
                    medication.StartDate = DateTime.UtcNow;

                MedicationStore[patientId].Add(medication);
            }

            LogAudit("CREATE", "Medication", patientId,
                $"Added medication: {medication.Name} ({medication.RxNormCode}), Dosage: {medication.Dosage}");

            return new HealthcareServiceResponse
            {
                Success = true,
                Message = $"Medication {medication.Name} added for patient {patientId}.",
                TransactionId = GenerateTransactionId(),
                Timestamp = DateTime.UtcNow
            };
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            LogAudit("ERROR", "Medication", patientId, $"Add medication failed: {ex.Message}");

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred.",
                    Timestamp = DateTime.UtcNow,
                    TransactionId = GenerateTransactionId()
                },
                new FaultReason("Internal server error."));
        }
    }

    public HealthcareServiceResponse DiscontinueMedication(string patientId, string rxNormCode, string reason)
    {
        try
        {
            lock (LockObject)
            {
                if (!MedicationStore.ContainsKey(patientId))
                {
                    throw new FaultException<HealthcareFault>(
                        new HealthcareFault
                        {
                            ErrorCode = "NOT_FOUND",
                            ErrorMessage = "No medications found for patient.",
                            Timestamp = DateTime.UtcNow,
                            TransactionId = GenerateTransactionId()
                        },
                        new FaultReason("Medication not found."));
                }

                var medication = MedicationStore[patientId]
                    .Find(m => m.RxNormCode == rxNormCode && m.IsActive);

                if (medication == null)
                {
                    throw new FaultException<HealthcareFault>(
                        new HealthcareFault
                        {
                            ErrorCode = "MEDICATION_NOT_FOUND",
                            ErrorMessage = $"Active medication {rxNormCode} not found for patient.",
                            Timestamp = DateTime.UtcNow,
                            TransactionId = GenerateTransactionId()
                        },
                        new FaultReason("Medication not found."));
                }

                medication.IsActive = false;
                medication.EndDate = DateTime.UtcNow;
            }

            LogAudit("UPDATE", "Medication", patientId,
                $"Discontinued medication {rxNormCode}. Reason: {reason}");

            return new HealthcareServiceResponse
            {
                Success = true,
                Message = $"Medication {rxNormCode} discontinued.",
                TransactionId = GenerateTransactionId(),
                Timestamp = DateTime.UtcNow
            };
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            LogAudit("ERROR", "Medication", patientId, $"Discontinue failed: {ex.Message}");

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred.",
                    Timestamp = DateTime.UtcNow,
                    TransactionId = GenerateTransactionId()
                },
                new FaultReason("Internal server error."));
        }
    }

