    public HealthcareServiceResponse RecordVitalSigns(string patientId, VitalSigns vitalSigns)
    {
        try
        {
            lock (LockObject)
            {
                if (!PatientStore.ContainsKey(patientId))
                {
                    throw new FaultException<HealthcareFault>(
                        new HealthcareFault
                        {
                            ErrorCode = "PATIENT_NOT_FOUND",
                            ErrorMessage = $"Patient {patientId} not found.",
                            Timestamp = DateTime.UtcNow,
                            TransactionId = GenerateTransactionId()
                        },
                        new FaultReason("Patient not found."));
                }

                if (!VitalSignsStore.ContainsKey(patientId))
                    VitalSignsStore[patientId] = new List<VitalSigns>();

                if (vitalSigns.MeasurementDate == default)
                    vitalSigns.MeasurementDate = DateTime.UtcNow;

                // Calculate BMI if height and weight are provided
                if (vitalSigns.Height.HasValue && vitalSigns.Weight.HasValue && vitalSigns.Height.Value > 0)
                {
                    double heightInMeters = vitalSigns.Height.Value / 100.0;
                    vitalSigns.BMI = Math.Round(vitalSigns.Weight.Value / (heightInMeters * heightInMeters), 1);
                }

                VitalSignsStore[patientId].Add(vitalSigns);
            }

            LogAudit("CREATE", "VitalSigns", patientId,
                $"Recorded vital signs. BP: {vitalSigns.BloodPressureSystolic}/{vitalSigns.BloodPressureDiastolic}, " +
                $"HR: {vitalSigns.HeartRate}, Temp: {vitalSigns.Temperature}");

            return new HealthcareServiceResponse
            {
                Success = true,
                Message = $"Vital signs recorded for patient {patientId}.",
                TransactionId = GenerateTransactionId(),
                Timestamp = DateTime.UtcNow
            };
        }
        catch (FaultException)
        {
            throw;
        }
        catch (Exception ex)
        {
            LogAudit("ERROR", "VitalSigns", patientId, $"Record vital signs failed: {ex.Message}");

            throw new FaultException<HealthcareFault>(
                new HealthcareFault
                {
                    ErrorCode = "INTERNAL_ERROR",
                    ErrorMessage = "An internal error occurred.",
                    Timestamp = DateTime.UtcNow,
                    TransactionId = GenerateTransactionId()
                },
                new FaultReason("Internal server error."));
        }
    }

