// ===== Custom Username Password Validator =====

public class HipaaUsernamePasswordValidator : System.IdentityModel.Selectors.UserNamePasswordValidator
{
    // In production, this would validate against a secure identity store
    private static readonly Dictionary<string, string> AuthorizedUsers = new Dictionary<string, string>
    {
        { "dr.smith", "SecureP@ss123!" },
        { "nurse.jones", "SecureP@ss456!" },
        { "admin.system", "SecureP@ss789!" },
        { "lab.tech", "SecureP@ss012!" }
    };

    public override void Validate(string userName, string password)
    {
        if (string.IsNullOrWhiteSpace(userName) || string.IsNullOrWhiteSpace(password))
        {
            throw new SecurityTokenValidationException("Username and password are required.");
        }

        if (!AuthorizedUsers.ContainsKey(userName) || AuthorizedUsers[userName] != password)
        {
            Console.WriteLine($"[SECURITY] Failed authentication attempt for user: {userName} at {DateTime.UtcNow:O}");
            throw new SecurityTokenValidationException("Invalid username or password.");
        }

        Console.WriteLine($"[SECURITY] Successful authentication for user: {userName} at {DateTime.UtcNow:O}");
    }
}

// ===== Security Configuration Helper =====

public static class WsSecurityConfiguration
{
    public static CustomBinding CreateSecureBinding()
    {
        // Create security binding element with message-level security
        var securityElement = SecurityBindingElement.CreateUserNameOverTransportBindingElement();
        securityElement.IncludeTimestamp = true;
        securityElement.MessageSecurityVersion = MessageSecurityVersion
            .WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10;

        // Set security header layout
        securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;

        // Configure encryption algorithm suite (AES-256 for HIPAA compliance)
        securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        // Local service settings
        securityElement.LocalServiceSettings.MaxClockSkew = TimeSpan.FromMinutes(5);
        securityElement.LocalServiceSettings.TimestampValidityDuration = TimeSpan.FromMinutes(10);
        securityElement.LocalServiceSettings.DetectReplays = true;
        securityElement.LocalServiceSettings.ReplayWindow = TimeSpan.FromMinutes(5);
        securityElement.LocalServiceSettings.MaxPendingSessions = 128;

        // Text message encoding
        var textEncoding = new TextMessageEncodingBindingElement
        {
            MessageVersion = MessageVersion.Soap12WSAddressing10
        };
        textEncoding.ReaderQuotas.MaxStringContentLength = 1048576;
        textEncoding.ReaderQuotas.MaxArrayLength = 1048576;
        textEncoding.ReaderQuotas.MaxDepth = 64;

        // HTTPS transport
        var httpsTransport = new HttpsTransportBindingElement
        {
            MaxReceivedMessageSize = 10485760,
            MaxBufferSize = 10485760,
            RequireClientCertificate = false
        };

        var binding = new CustomBinding(securityElement, textEncoding, httpsTransport);
        binding.ReceiveTimeout = TimeSpan.FromMinutes(10);
        binding.SendTimeout = TimeSpan.FromMinutes(10);

        return binding;
    }

    public static CustomBinding CreateMutualCertificateBinding()
    {
        // Mutual certificate authentication for system-to-system communication
        var securityElement = SecurityBindingElement.CreateMutualCertificateBindingElement(
            MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

        securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;
        securityElement.IncludeTimestamp = true;
        securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;
        securityElement.SetKeyDerivation(true);

        // Enable signature confirmation
        securityElement.RequireSignatureConfirmation = true;

        // Local service settings for replay detection
        securityElement.LocalServiceSettings.DetectReplays = true;
        securityElement.LocalServiceSettings.ReplayWindow = TimeSpan.FromMinutes(5);
        securityElement.LocalServiceSettings.MaxClockSkew = TimeSpan.FromMinutes(5);

        var textEncoding = new TextMessageEncodingBindingElement
        {
            MessageVersion = MessageVersion.Soap12WSAddressing10
        };

        var httpTransport = new HttpTransportBindingElement
        {
            MaxReceivedMessageSize = 10485760,
            MaxBufferSize = 10485760
        };

        return new CustomBinding(securityElement, textEncoding, httpTransport);
    }

    public static WSHttpBinding CreateWsHttpSecureBinding()
    {
        var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
        {
            MaxReceivedMessageSize = 10485760,
            MaxBufferPoolSize = 10485760,
            ReaderQuotas =
            {
                MaxStringContentLength = 1048576,
                MaxArrayLength = 1048576,
                MaxDepth = 64
            },
            ReceiveTimeout = TimeSpan.FromMinutes(10),
            SendTimeout = TimeSpan.FromMinutes(10)
        };

        // Message security with username credentials
        binding.Security.Message.ClientCredentialType = MessageCredentialType.UserName;
        binding.Security.Message.EstablishSecurityContext = true;
        binding.Security.Message.NegotiateServiceCredential = true;
        binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

        // Transport security
        binding.Security.Transport.ClientCredentialType = HttpClientCredentialType.None;

        return binding;
    }
}

// ===== Service Host Configuration =====

public class HealthcareServiceHost
{
    private ServiceHost _serviceHost;
    private readonly string _baseAddress;
    private readonly string _certificateThumbprint;
    private readonly StoreLocation _certificateStoreLocation;

    public HealthcareServiceHost(
        string baseAddress = "https://localhost:8443/healthcare",
        string certificateThumbprint = null,
        StoreLocation certificateStoreLocation = StoreLocation.LocalMachine)
    {
        _baseAddress = baseAddress;
        _certificateThumbprint = certificateThumbprint;
        _certificateStoreLocation = certificateStoreLocation;
    }

    public void Start()
    {
        try
        {
            _serviceHost = new ServiceHost(typeof(HealthcareRecordService), new Uri(_baseAddress));

            ConfigureServiceBehavior();
            ConfigureEndpoints();
            ConfigureCredentials();

            _serviceHost.Opening += (s, e) => Console.WriteLine("[SERVICE] Healthcare service is opening...");
            _serviceHost.Opened += (s, e) => Console.WriteLine($"[SERVICE] Healthcare service started at {_baseAddress}");
            _serviceHost.Closing += (s, e) => Console.WriteLine("[SERVICE] Healthcare service is closing...");
            _serviceHost.Closed += (s, e) => Console.WriteLine("[SERVICE] Healthcare service stopped.");
            _serviceHost.Faulted += (s, e) =>
            {
                Console.WriteLine("[SERVICE] Healthcare service faulted! Attempting recovery...");
                RecoverFromFault();
            };

            _serviceHost.Open();

            PrintEndpointInfo();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"[ERROR] Failed to start healthcare service: {ex.Message}");
            throw;
        }
    }

    private void ConfigureServiceBehavior()
    {
        var serviceBehavior = _serviceHost.Description.Behaviors.Find<ServiceBehaviorAttribute>();
        if (serviceBehavior == null)
        {
            serviceBehavior = new ServiceBehaviorAttribute();
            _serviceHost.Description.Behaviors.Add(serviceBehavior);
        }

        // Metadata behavior
        var metadataBehavior = _serviceHost.Description.Behaviors.Find<ServiceMetadataBehavior>();
        if (metadataBehavior == null)
        {
            metadataBehavior = new ServiceMetadataBehavior
            {
                HttpsGetEnabled = true,
                HttpsGetUrl = new Uri(_baseAddress + "/mex")
            };
            _serviceHost.Description.Behaviors.Add(metadataBehavior);
        }

        // Service debug behavior - disable in production
        var debugBehavior = _serviceHost.Description.Behaviors.Find<ServiceDebugBehavior>();
        if (debugBehavior == null)
        {
            debugBehavior = new ServiceDebugBehavior { IncludeExceptionDetailInFaults = false };
            _serviceHost.Description.Behaviors.Add(debugBehavior);
        }
        else
        {
            debugBehavior.IncludeExceptionDetailInFaults = false;
        }

        // Throttling behavior
        var throttleBehavior = _serviceHost.Description.Behaviors.Find<ServiceThrottlingBehavior>();
        if (throttleBehavior == null)
        {
            throttleBehavior = new ServiceThrottlingBehavior
            {
                MaxConcurrentCalls = 100,
                MaxConcurrentInstances = 100,
                MaxConcurrentSessions = 50
            };
            _serviceHost.Description.Behaviors.Add(throttleBehavior);
        }
    }

    private void ConfigureEndpoints()
    {
        // Primary endpoint with WS-Security (Username over Transport)
        var wsHttpBinding = WsSecurityConfiguration.CreateWsHttpSecureBinding();
        _serviceHost.AddServiceEndpoint(
            typeof(IHealthcareRecordService),
            wsHttpBinding,
            "");

        // MEX endpoint
        _serviceHost.AddServiceEndpoint(
            typeof(IMetadataExchange),
            MetadataExchangeBindings.CreateMexHttpsBinding(),
            "mex");
    }

    private void ConfigureCredentials()
    {
        var credentials = _serviceHost.Credentials;

        // Configure service certificate for message encryption
        if (!string.IsNullOrEmpty(_certificateThumbprint))
        {
            credentials.ServiceCertificate.SetCertificate(
                _certificateStoreLocation,
                StoreName.My,
                X509FindType.FindByThumbprint,
                _certificateThumbprint);
        }
        else
        {
            // For development/testing - use a self-signed certificate
            Console.WriteLine("[WARNING] No certificate thumbprint configured. Using development certificate settings.");
            Console.WriteLine("[WARNING] In production, configure a proper X.509 certificate for HIPAA compliance.");
        }

        // Custom username/password validation
        credentials.UserNameAuthentication.UserNamePasswordValidationMode =
            System.ServiceModel.Security.UserNamePasswordValidationMode.Custom;
        credentials.UserNameAuthentication.CustomUserNamePasswordValidator =
            new HipaaUsernamePasswordValidator();

        // Certificate validation for client certificates (if using mutual cert auth)
        credentials.ClientCertificate.Authentication.CertificateValidationMode =
            System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
        credentials.ClientCertificate.Authentication.RevocationMode = X509RevocationMode.Online;
    }

    private void PrintEndpointInfo()
    {
        Console.WriteLine("\n========== HEALTHCARE SERVICE ENDPOINTS ==========");
        foreach (var endpoint in _serviceHost.Description.Endpoints)
        {
            Console.WriteLine($"  Endpoint: {endpoint.Address}");
            Console.WriteLine($"  Binding:  {endpoint.Binding.Name}");
            Console.WriteLine($"  Contract: {endpoint.Contract.Name}");

            if (endpoint.Binding is WSHttpBinding wsBinding)
            {
                Console.WriteLine($"  Security Mode: {wsBinding.Security.Mode}");
                Console.WriteLine($"  Message Credential: {wsBinding.Security.Message.ClientCredentialType}");
                Console.WriteLine($"  Algorithm Suite: {wsBinding.Security.Message.AlgorithmSuite}");
            }
            Console.WriteLine("  ---");
        }
        Console.WriteLine("==================================================\n");
    }

    private void RecoverFromFault()
    {
        try
        {
            _serviceHost?.Abort();
            Start();
        }
        catch (Exception ex)
        {
            Console.WriteLine($"[ERROR] Recovery failed: {ex.Message}");
        }
    }

    public void Stop()
    {
        try
        {
            if (_serviceHost != null &&
                _serviceHost.State != CommunicationState.Faulted)
            {
                _serviceHost.Close(TimeSpan.FromSeconds(30));
            }
            else
            {
                _serviceHost?.Abort();
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"[ERROR] Error stopping service: {ex.Message}");
            _serviceHost?.Abort();
        }
    }
}

// ===== Client Proxy Helper =====

public class HealthcareServiceClient : IDisposable
{
    private readonly ChannelFactory<IHealthcareRecordService> _channelFactory;
    private IHealthcareRecordService _channel;
    private bool _disposed;

    public HealthcareServiceClient(string endpointAddress, string username, string password,
        string serverCertificateThumbprint = null)
    {
        var binding = WsSecurityConfiguration.CreateWsHttpSecureBinding();

        var endpointAddr = new EndpointAddress(
            new Uri(endpointAddress),
            EndpointIdentity.CreateDnsIdentity("localhost"));

        _channelFactory = new ChannelFactory<IHealthcareRecordService>(binding, endpointAddr);

        // Set credentials
        _channelFactory.Credentials.UserName.UserName = username;
        _channelFactory.Credentials.UserName.Password = password;

        // Certificate validation (for development, accept self-signed)
        if (string.IsNullOrEmpty(serverCertificateThumbprint))
        {
            _channelFactory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
                System.ServiceModel.Security.X509CertificateValidationMode.None;
        }
        else
        {
            _channelFactory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
                System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
        }
    }

    public IHealthcareRecordService Channel
    {
        get
        {
            if (_channel == null || ((ICommunicationObject)_channel).State == CommunicationState.Faulted)
            {
                _channel = _channelFactory.CreateChannel();
                ((ICommunicationObject)_channel).Open();
            }
            return _channel;
        }
    }

    public void Dispose()
    {
        if (_disposed) return;
        _disposed = true;

        try
        {
            if (_channel != null)
            {
                var commObj = (ICommunicationObject)_channel;
                if (commObj.State == CommunicationState.Faulted)
                    commObj.Abort();
                else
                    commObj.Close();
            }

            if (_channelFactory.State == CommunicationState.Faulted)
                _channelFactory.Abort();
            else
                _channelFactory.Close();
        }
        catch
        {
            _channelFactory?.Abort();
        }
    }
}

